import React, { createContext, useContext, useState, useEffect } from 'react';
import AsyncStorage from '@react-native-async-storage/async-storage';

type SettingsContextType = {
  temperatureUnit: 'C' | 'F';
  toggleTemperatureUnit: () => void;
  updateUserName: (name: string) => Promise<void>;
  userName: string;
};

const SettingsContext = createContext<SettingsContextType | undefined>(undefined);

export const useSettings = () => {
  const context = useContext(SettingsContext);
  if (!context) {
    throw new Error('useSettings must be used within a SettingsProvider');
  }
  return context;
};

export const SettingsProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [temperatureUnit, setTemperatureUnit] = useState<'C' | 'F'>('C');
  const [userName, setUserName] = useState('');

  useEffect(() => {
    // Load saved settings on mount
    const loadSettings = async () => {
      try {
        const savedUnit = await AsyncStorage.getItem('temperatureUnit');
        const savedName = await AsyncStorage.getItem('userName');
        if (savedUnit) setTemperatureUnit(savedUnit as 'C' | 'F');
        if (savedName) setUserName(savedName);
      } catch (error) {
        console.error('Error loading settings:', error);
      }
    };
    loadSettings();
  }, []);

  const toggleTemperatureUnit = async () => {
    const newUnit = temperatureUnit === 'C' ? 'F' : 'C';
    setTemperatureUnit(newUnit);
    try {
      await AsyncStorage.setItem('temperatureUnit', newUnit);
    } catch (error) {
      console.error('Error saving temperature unit:', error);
    }
  };

  const updateUserName = async (name: string) => {
    setUserName(name);
    try {
      await AsyncStorage.setItem('userName', name);
    } catch (error) {
      console.error('Error saving user name:', error);
    }
  };

  return (
    <SettingsContext.Provider value={{
      temperatureUnit,
      toggleTemperatureUnit,
      updateUserName,
      userName
    }}>
      {children}
    </SettingsContext.Provider>
  );
};
